mapper.select:
SELECT OBJECTID as objectId, NAME as tableNameCh,TABLENAME as tableNameEn,SJXJBM as resourceIdentify from
CLASSIFY_INTERFACE_ALL_DATE
where SJXJBM is not null and PRIMARYORGANIZATIONCH = #{primaryClassifyCh} and objectstate = 1

    and SECONDARYORGANIZATIONCH = #{secondaryClassifyCh}


    and 'JZCODEGASJZZFL'||SJYJFLCODENAME||SJEJFLCODENAME||SJSJFLCODENAME = #{classifyid}


    and
    (NAME like '%${search}%' or
    upper(TABLENAME) like upper('%${search}%') or
    upper(SJXJBM) like upper('%${search}%')
    )

select SJXJBM as resourceIdentify,YYYXTJSGS as manufacturer,SJZYSQDWMC as authority from SYNLTE.PUBLIC_DATA_INFO where
SJXJBM is not null
and (YYYXTJSGS is not null or SJZYSQDWMC is not null)

    and YYYXTJSGS = #{manufacturer}


    and SJZYSQDWMC = #{authority}

SELECT SJXJBM as resourceIdentify ,TABLE_TYPE||'.'||TABLE_PROJECT as storageLocation,TABLE_ALL_COUNT as dataNum, resourceId FROM ( SELECT j.SJXJBM,j.TABLE_TYPE,j.TABLE_PROJECT,j.TABLE_ALL_COUNT,resourceId, row_number ( ) over ( PARTITION BY lower( TABLE_PROJECT ), upper( TABLE_NAME_EN ) ORDER BY STATISTICS_TIME DESC ) AS rnn FROM table_organization_assets j left join synlte.object_store_info h on upper(j.table_name_en)=upper(h.tablename) and upper(j.table_project)=upper(h.project_name) WHERE PRIMARY_ORGANIZATION_CH = #{primaryClassifyCh}
and SECONDARY_ORGANIZATION_CH = #{secondaryClassifyCh}
and upper(TABLE_TYPE) in ('ODPS','HIVE') and STATISTICS_TIME >= trunc (sysdate) and h.import_flag=1 ) h WHERE h.rnn =1
